/* ═══════════════════════════════════════════════
   Paragraph Comment Layer (pcl-)
   ═══════════════════════════════════════════════ */

/* Warm paragraph hover — signals commentability (JS .pcl-active only) */
.chapter-reader-content .editor-paragraph[data-paragraph-index] {
    transition: background-color 0.25s ease;
    border-radius: 3px;
}

.pcl-layer {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    pointer-events: none;
    z-index: 1;
}

.pcl-badge-anchor {
    position: absolute;
    right: -4px;
    pointer-events: none;
    display: flex;
    align-items: flex-start;
    padding-top: 3px;
    padding-left: 20px;
    opacity: 0;
    transition: opacity 0.15s ease;
}

.pcl-badge-anchor.pcl-badge-visible {
    opacity: 1;
    pointer-events: auto;
}

.pcl-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 5px 8px;
    border: 1px solid var(--bg-glass-border);
    border-radius: 20px;
    background: var(--bg-glass);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    color: var(--text-secondary);
    cursor: pointer;
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    white-space: nowrap;
    box-shadow: var(--shadow-card-sm);
    transition: color 0.2s ease, border-color 0.2s ease,
                background-color 0.2s ease, box-shadow 0.2s ease,
                transform 0.2s ease;
}

.pcl-badge:hover {
    color: var(--accent-amber);
    border-color: var(--accent-amber);
    background: var(--bg-selection-active);
    box-shadow: 0 0 0 3px var(--bg-selection), var(--shadow-card-sm);
    transform: scale(1.06);
}

.pcl-badge-active {
    color: var(--accent-amber);
    border-color: rgba(212, 168, 83, 0.3);
    background: var(--bg-selection);
    box-shadow: 0 0 12px rgba(212, 168, 83, 0.1);
}

.pcl-badge-active:hover {
    border-color: var(--accent-amber);
    background: var(--bg-selection-active);
    box-shadow: 0 0 0 3px var(--bg-selection-active),
                0 0 16px rgba(212, 168, 83, 0.14);
}

.pcl-badge svg {
    flex-shrink: 0;
}

.pcl-badge-count {
    line-height: 1;
    min-width: 8px;
    text-align: center;
}

@media (max-width: 768px) {
    .pcl-badge {
        padding: 4px 6px;
        font-size: 0.64rem;
    }
}

/* JS-driven active state — highlight only on explicit hover/click, not scroll */
.chapter-reader-content .editor-paragraph[data-paragraph-index].pcl-active {
    background-color: var(--bg-selection);
}


/* ═══════════════════════════════════════════════
   Comment Panel (cp-)
   ═══════════════════════════════════════════════ */

.cp-backdrop {
    position: fixed;
    inset: 0;
    background: var(--bg-overlay);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    z-index: 200;
}

.cp-panel {
    display: flex;
    flex-direction: column;
    background: var(--bg-card);
    z-index: 201;
    overflow: hidden;
    box-shadow: var(--shadow-modal);
}

.cp-panel-desktop {
    position: fixed;
    top: 0;
    right: 0;
    width: 380px;
    height: 100%;
    border-left: 1px solid var(--border-card);
}

.cp-panel-mobile {
    position: fixed;

